import { useState, useEffect, lazy, Suspense, useMemo } from "react";
import { useForm, Controller } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { useTranslation } from "react-i18next";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { CalendarIcon, Upload, X, Globe, Pin, ArrowUpDown, Store, FileEdit, Send, Image, Video, Plus, Trash2, Search } from "lucide-react";

// Type for date range
interface DateRange {
  start: number;
  end: number;
}
import { format } from "date-fns";
import { cn } from "@/lib/utils";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { useQuery, useQueryClient } from "@tanstack/react-query";
const LazyRichTextEditor = lazy(() => import("./RichTextEditor").then(m => ({ default: m.RichTextEditor })));
import { ScrollArea } from "@/components/ui/scroll-area";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";
import { Skeleton } from "@/components/ui/skeleton";
import { ImageCropDialog } from "./ImageCropDialog";
import i18n from "@/i18n/config";

// Draft schema - no required fields except status
const draftSchema = z.object({
  title_en: z.string().optional(),
  title_zh: z.string().optional(),
  title_pt: z.string().optional(),
  intro_zh: z.string().optional(),
  intro_en: z.string().optional(),
  intro_pt: z.string().optional(),
  content_en: z.string().optional(),
  content_zh: z.string().optional(),
  content_pt: z.string().optional(),
  usage_instructions_zh: z.string().optional(),
  usage_instructions_en: z.string().optional(),
  usage_instructions_pt: z.string().optional(),
  start_date: z.date().optional(),
  end_date: z.date().optional(),
  repeat_mode: z.enum(["none", "daily", "weekly", "monthly", "yearly", "days_before"]).optional(),
  repeat_weekday: z.number().min(0).max(6).optional().nullable(),
  repeat_days_before: z.number().min(0).max(30).optional().nullable(),
  repeat_month_day: z.array(z.object({ start: z.number().min(1).max(31), end: z.number().min(1).max(31) })).optional().nullable(),
  repeat_yearly_month: z.number().min(1).max(12).optional().nullable(),
  repeat_yearly_day: z.number().min(1).max(31).optional().nullable(),
  service_type: z.enum(["dine_in", "takeaway", "both"]).optional(),
  status: z.enum(["draft", "published"]).default("draft"),
  pinned: z.boolean().default(false),
  visible: z.boolean().default(false),
  sort_order: z.number().default(0),
  badge_text_zh: z.string().optional(),
  badge_text_en: z.string().optional(),
  badge_text_pt: z.string().optional(),
  badge_color: z.string().optional(),
  discount_type: z.enum(["percentage", "fixed_amount"]).optional().nullable(),
  discount_value: z.number().optional().nullable(),
  discount_key: z.string().optional().nullable()
});

// Published schema - only Chinese fields required; EN/PT auto-translated if empty
const publishedSchema = z.object({
  title_en: z.string().optional(),
  title_zh: z.string().min(1, i18n.t("validation.titleRequired")),
  title_pt: z.string().optional(),
  intro_zh: z.string().optional(),
  intro_en: z.string().optional(),
  intro_pt: z.string().optional(),
  content_en: z.string().optional(),
  content_zh: z.string().min(1, i18n.t("validation.contentRequired")),
  content_pt: z.string().optional(),
  usage_instructions_zh: z.string().optional(),
  usage_instructions_en: z.string().optional(),
  usage_instructions_pt: z.string().optional(),
  start_date: z.date(),
  end_date: z.date().optional(),
  repeat_mode: z.enum(["none", "daily", "weekly", "monthly", "yearly", "days_before"]),
  repeat_weekday: z.number().min(0).max(6).optional().nullable(),
  repeat_days_before: z.number().min(0).max(30).optional().nullable(),
  repeat_month_day: z.array(z.object({ start: z.number().min(1).max(31), end: z.number().min(1).max(31) })).optional().nullable(),
  repeat_yearly_month: z.number().min(1).max(12).optional().nullable(),
  repeat_yearly_day: z.number().min(1).max(31).optional().nullable(),
  service_type: z.enum(["dine_in", "takeaway", "both"]),
  status: z.enum(["draft", "published"]).default("published"),
  pinned: z.boolean().default(false),
  visible: z.boolean().default(true),
  sort_order: z.number().default(0),
  badge_text_zh: z.string().optional(),
  badge_text_en: z.string().optional(),
  badge_text_pt: z.string().optional(),
  badge_color: z.string().optional(),
  discount_type: z.enum(["percentage", "fixed_amount"]).optional().nullable(),
  discount_value: z.number().optional().nullable(),
  discount_key: z.string().optional().nullable()
});

// Base schema for form (uses draft schema, validation happens on submit)
const activitySchema = draftSchema;
type ActivityFormData = z.infer<typeof activitySchema>;
interface ActivityFormDialogProps {
  activity?: any;
  trigger: React.ReactNode;
}
export function ActivityFormDialog({
  activity,
  trigger
}: ActivityFormDialogProps) {
  const {
    t
  } = useTranslation();
  const queryClient = useQueryClient();
  const [open, setOpen] = useState(false);
  const [contentLangTab, setContentLangTab] = useState("zh");
  const [editorsReady, setEditorsReady] = useState(false);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(activity?.image_url || null);
  const [selectedRestaurants, setSelectedRestaurants] = useState<string[]>([]);
  const [restaurantSearch, setRestaurantSearch] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showCropDialog, setShowCropDialog] = useState(false);
  const [tempImageFile, setTempImageFile] = useState<File | null>(null);
  const [mediaType, setMediaType] = useState<"image" | "video">(activity?.media_type === "video" ? "video" : "image");
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [videoPreview, setVideoPreview] = useState<string | null>(activity?.video_url || null);
  const [isUploadingVideo, setIsUploadingVideo] = useState(false);
  const [videoDeleted, setVideoDeleted] = useState(false);
  const {
    data: restaurants,
    isLoading: isRestaurantsLoading
  } = useQuery({
    queryKey: ["activity-restaurant-options", open, restaurantSearch],
    enabled: open,
    staleTime: 1000 * 60 * 5,
    queryFn: async () => {
      const keyword = restaurantSearch.trim();
      let query = supabase
        .from("restaurants")
        .select("id,name,name_en,name_pt,address")
        .eq("visible", true)
        .order("name", { ascending: true })
        .limit(keyword ? 80 : 40);

      if (keyword) {
        query = query.or([
          `name.ilike.%${keyword}%`,
          `name_en.ilike.%${keyword}%`,
          `name_pt.ilike.%${keyword}%`,
          `address.ilike.%${keyword}%`
        ].join(","));
      }

      const { data, error } = await query;
      if (error) throw error;
      return data ?? [];
    }
  });
  const selectedRestaurantIds = useMemo(() => new Set(selectedRestaurants), [selectedRestaurants]);
  const hasRestaurantSearch = restaurantSearch.trim().length > 0;
  const getDefaultValues = (): ActivityFormData => activity ? {
    title_en: activity.title_en,
    title_zh: activity.title_zh,
    title_pt: activity.title_pt,
    intro_zh: activity.intro_zh || "",
    intro_en: activity.intro_en || "",
    intro_pt: activity.intro_pt || "",
    content_en: activity.content_en,
    content_zh: activity.content_zh,
    content_pt: activity.content_pt,
    usage_instructions_zh: activity.usage_instructions_zh || "",
    usage_instructions_en: activity.usage_instructions_en || "",
    usage_instructions_pt: activity.usage_instructions_pt || "",
    start_date: new Date(activity.start_date),
    end_date: activity.end_date ? new Date(activity.end_date) : undefined,
    repeat_mode: (activity.repeat_mode || "none") as "none" | "daily" | "weekly" | "monthly" | "yearly" | "days_before",
    repeat_weekday: activity.repeat_weekday ?? null,
    repeat_days_before: activity.repeat_days_before ?? null,
    repeat_month_day: Array.isArray(activity.repeat_month_day) ? activity.repeat_month_day : null,
    repeat_yearly_month: activity.repeat_yearly_month ?? null,
    repeat_yearly_day: activity.repeat_yearly_day ?? null,
    service_type: (activity.service_type || "both") as "dine_in" | "takeaway" | "both",
    status: (activity.status || "draft") as "draft" | "published",
    pinned: activity.pinned || false,
    visible: activity.visible !== undefined ? activity.visible : true,
    sort_order: activity.sort_order || 0,
    badge_text_zh: activity.badge_text_zh || activity.title_zh,
    badge_text_en: activity.badge_text_en || activity.title_en,
    badge_text_pt: activity.badge_text_pt || activity.title_pt,
    badge_color: activity.badge_color || "#9b87f5",
    discount_type: activity.discount_type || null,
    discount_value: activity.discount_value || null,
    discount_key: activity.discount_key || null
  } : {
    repeat_mode: "none" as const,
    repeat_weekday: null,
    repeat_days_before: null,
    repeat_month_day: null,
    repeat_yearly_month: null,
    repeat_yearly_day: null,
    service_type: "both" as const,
    status: "draft" as const,
    pinned: false,
    visible: false,
    sort_order: 0,
    badge_color: "#9b87f5",
    discount_type: null,
    discount_value: null,
    discount_key: null
  };

  const {
    register,
    handleSubmit,
    formState: {
      errors
    },
    setValue,
    watch,
    control,
    reset
  } = useForm<ActivityFormData>({
    resolver: zodResolver(activitySchema),
    defaultValues: getDefaultValues()
  });

  // Reset form when dialog opens or closes
  const handleOpenChange = (newOpen: boolean) => {
    if (newOpen) {
      // Reset form to latest data when opening
      reset(getDefaultValues());
      setImageFile(null);
      setImagePreview(activity?.image_url || null);
      setVideoFile(null);
      setVideoPreview(activity?.video_url || null);
      setVideoDeleted(false);
      setMediaType(activity?.media_type === "video" ? "video" : "image");
      setIsUploadingVideo(false);
      setShowCropDialog(false);
      setTempImageFile(null);
      setRestaurantSearch("");
      setEditorsReady(false);
      // Delay editor mounting to avoid blocking the UI thread
      setTimeout(() => setEditorsReady(true), 300);
    } else {
      // Reset form to original values when closing
      reset(getDefaultValues());
      setImageFile(null);
      setImagePreview(activity?.image_url || null);
      setVideoFile(null);
      setVideoPreview(activity?.video_url || null);
      setVideoDeleted(false);
      setMediaType(activity?.media_type === "video" ? "video" : "image");
    }
    setOpen(newOpen);
  };
  const startDate = watch("start_date");
  const endDate = watch("end_date");
  const pinned = watch("pinned");
  const visible = watch("visible");
  const status = watch("status");

  // Sync visible with status - draft always has visible=false
  useEffect(() => {
    if (status === "draft") {
      setValue("visible", false);
      setValue("pinned", false);
    }
  }, [status, setValue]);

  // Load associated restaurants when editing
  useEffect(() => {
    const loadAssociatedRestaurants = async () => {
      if (activity?.id) {
        const {
          data
        } = await supabase.from("activity_restaurants").select("restaurant_id").eq("activity_id", activity.id);
        if (data) {
          setSelectedRestaurants(data.map(ar => ar.restaurant_id));
        }
      }
    };
    loadAssociatedRestaurants();
  }, [activity?.id]);
  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      // Check file size (max 10MB)
      if (file.size > 10 * 1024 * 1024) {
        toast.error(t("admin.imageTooBig"));
        return;
      }
      setTempImageFile(file);
      setShowCropDialog(true);
    }
    // Reset input
    e.target.value = "";
  };

  const handleCropComplete = (croppedFile: File, preview: string) => {
    setImageFile(croppedFile);
    setImagePreview(preview);
  };

  const handleVideoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      // Check file size (max 100MB)
      if (file.size > 100 * 1024 * 1024) {
        toast.error(t("admin.videoTooBig"));
        return;
      }
      // Check file type
      if (!file.type.startsWith("video/")) {
        toast.error(t("admin.invalidVideoFormat"));
        return;
      }
      setVideoFile(file);
      setVideoPreview(URL.createObjectURL(file));
      setVideoDeleted(false); // Reset deleted flag when new video is uploaded
    }
    e.target.value = "";
  };

  const uploadImage = async (): Promise<string | null> => {
    if (!imageFile) return activity?.image_url || null;
    const fileExt = imageFile.name.split(".").pop();
    const fileName = `${Math.random()}.${fileExt}`;
    const filePath = `${fileName}`;
    const {
      error: uploadError
    } = await supabase.storage.from("activity-images").upload(filePath, imageFile);
    if (uploadError) {
      throw uploadError;
    }
    const {
      data: {
        publicUrl
      }
    } = supabase.storage.from("activity-images").getPublicUrl(filePath);
    return publicUrl;
  };

  const uploadVideo = async (): Promise<string | null> => {
    // If user explicitly deleted video, return null
    if (videoDeleted && !videoFile) return null;
    if (!videoFile) return activity?.video_url || null;
    setIsUploadingVideo(true);
    try {
      const fileExt = videoFile.name.split(".").pop();
      const fileName = `video_${Date.now()}.${fileExt}`;
      const { error: uploadError } = await supabase.storage
        .from("activity-images")
        .upload(fileName, videoFile);
      if (uploadError) throw uploadError;
      const { data: { publicUrl } } = supabase.storage
        .from("activity-images")
        .getPublicUrl(fileName);
      return publicUrl;
    } finally {
      setIsUploadingVideo(false);
    }
  };
  const onSubmit = async (data: ActivityFormData) => {
    setIsSubmitting(true);
    try {
      // If publishing, validate with publishedSchema
      if (data.status === "published") {
        const publishedResult = publishedSchema.safeParse(data);
        if (!publishedResult.success) {
          // Map field names to readable labels
          const fieldLabels: Record<string, string> = {
            title_zh: t("admin.titleChinese"),
            title_en: t("admin.titleEnglish"),
            title_pt: t("admin.titlePortuguese"),
            content_zh: t("admin.contentChinese"),
            content_en: t("admin.contentEnglish"),
            content_pt: t("admin.contentPortuguese"),
            start_date: t("admin.startDate"),
            end_date: t("admin.endDate"),
            repeat_mode: t("admin.repeatMode"),
            service_type: t("admin.serviceType")
          };
          
          // Collect all missing fields
          const missingFields = publishedResult.error.errors.map(err => {
            const fieldPath = err.path.join(".");
            return fieldLabels[fieldPath] || fieldPath;
          });
          
          // Show all missing fields in toast
          toast.error(`${t("admin.publishRequiresComplete")}: ${missingFields.join(", ")}`);
          setIsSubmitting(false);
          return;
        }
      }

      const {
        data: {
          user
        }
      } = await supabase.auth.getUser();
      if (!user) throw new Error("Not authenticated");
      // Upload image and video in parallel for better performance
      const [imageUrl, videoUrl] = await Promise.all([
        uploadImage(),
        uploadVideo()
      ]);

      // Draft activities always have visible=false
      const finalVisible = data.status === "draft" ? false : data.visible;

      // Auto-translate Chinese → EN/PT if empty
      let titleEn = data.title_en || "";
      let titlePt = data.title_pt || "";
      let contentEn = data.content_en || "";
      let contentPt = data.content_pt || "";
      let introEn = data.intro_en || null;
      let introPt = data.intro_pt || null;
      let usageEn = data.usage_instructions_en || null;
      let usagePt = data.usage_instructions_pt || null;
      let badgeEn = data.badge_text_en || "";
      let badgePt = data.badge_text_pt || "";

      const needsEnTranslation = !titleEn && data.title_zh;
      const needsPtTranslation = !titlePt && data.title_zh;

      if (needsEnTranslation || needsPtTranslation) {
        // Build translation text with separators
        const zhParts = [
          data.title_zh || "",
          data.content_zh || "",
          data.intro_zh || "",
          data.usage_instructions_zh || "",
          data.badge_text_zh || data.title_zh || "",
        ];
        const combinedZh = zhParts.join("\n---SECTION---\n");

        const translateToLang = async (lang: string) => {
          try {
            const { data: result } = await supabase.functions.invoke("translate-content", {
              body: { text: combinedZh, targetLang: lang },
            });
            if (result?.translatedText) {
              const parts = result.translatedText.split(/---SECTION---/);
              return parts.map((p: string) => p.trim());
            }
          } catch {}
          return null;
        };

        const [enParts, ptParts] = await Promise.all([
          needsEnTranslation ? translateToLang("en") : null,
          needsPtTranslation ? translateToLang("pt") : null,
        ]);

        if (enParts) {
          titleEn = enParts[0] || titleEn;
          contentEn = enParts[1] || contentEn;
          introEn = enParts[2] || introEn;
          usageEn = enParts[3] || usageEn;
          badgeEn = enParts[4] || badgeEn;
        }
        if (ptParts) {
          titlePt = ptParts[0] || titlePt;
          contentPt = ptParts[1] || contentPt;
          introPt = ptParts[2] || introPt;
          usagePt = ptParts[3] || usagePt;
          badgePt = ptParts[4] || badgePt;
        }
      }

      // Base activity data for both create and update
      const baseActivityData = {
        title_en: titleEn,
        title_zh: data.title_zh || "",
        title_pt: titlePt,
        intro_zh: data.intro_zh || null,
        intro_en: introEn,
        intro_pt: introPt,
        content_en: contentEn,
        content_zh: data.content_zh || "",
        content_pt: contentPt,
        usage_instructions_zh: data.usage_instructions_zh || null,
        usage_instructions_en: usageEn,
        usage_instructions_pt: usagePt,
        repeat_mode: data.repeat_mode || "none",
        repeat_weekday: data.repeat_mode === 'weekly' ? data.repeat_weekday : null,
        repeat_days_before: data.repeat_mode === 'days_before' ? data.repeat_days_before : null,
        repeat_month_day: data.repeat_mode === 'monthly' ? data.repeat_month_day : null,
        repeat_yearly_month: data.repeat_mode === 'yearly' ? data.repeat_yearly_month : null,
        repeat_yearly_day: data.repeat_mode === 'yearly' ? data.repeat_yearly_day : null,
        service_type: data.service_type || "both",
        status: data.status,
        pinned: data.status === "draft" ? false : data.pinned,
        visible: finalVisible,
        sort_order: data.sort_order,
        image_url: imageUrl,
        media_type: mediaType,
        video_url: videoUrl,
        start_date: data.start_date?.toISOString() || new Date().toISOString(),
        end_date: data.end_date?.toISOString() || null,
        badge_text_zh: data.badge_text_zh || data.title_zh || "",
        badge_text_en: badgeEn || titleEn,
        badge_text_pt: badgePt || titlePt,
        badge_color: data.badge_color || "#9b87f5",
        discount_type: data.discount_type || null,
        discount_value: data.discount_value || null,
        discount_key: data.discount_key || null
      };
      if (activity) {
        // Update activity - don't change creator_id
        const {
          error
        } = await supabase.from("activities").update(baseActivityData).eq("id", activity.id);
        if (error) throw error;

        // Update restaurant associations
        await supabase.from("activity_restaurants").delete().eq("activity_id", activity.id);
        if (selectedRestaurants.length > 0) {
          const associations = selectedRestaurants.map(restaurantId => ({
            activity_id: activity.id,
            restaurant_id: restaurantId
          }));
          const {
            error: assocError
          } = await supabase.from("activity_restaurants").insert(associations);
          if (assocError) throw assocError;
        }
        toast.success(t("admin.activityUpdated"));
        setOpen(false);
      } else {
        // Create activity - set creator_id for new activities
        const activityDataWithCreator = {
          ...baseActivityData,
          creator_id: user.id
        };
        const {
          data: newActivity,
          error
        } = await supabase.from("activities").insert([activityDataWithCreator]).select().single();
        if (error) throw error;

        // Add restaurant associations
        if (selectedRestaurants.length > 0) {
          const associations = selectedRestaurants.map(restaurantId => ({
            activity_id: newActivity.id,
            restaurant_id: restaurantId
          }));
          const {
            error: assocError
          } = await supabase.from("activity_restaurants").insert(associations);
          if (assocError) throw assocError;
        }

        // Auto-link coupon templates with auto_link_activities enabled
        const { data: autoLinkTemplates } = await supabase
          .from("coupon_templates")
          .select("id")
          .eq("auto_link_activities", true)
          .eq("is_active", true);

        if (autoLinkTemplates && autoLinkTemplates.length > 0) {
          const couponAssociations = autoLinkTemplates.map(template => ({
            coupon_template_id: template.id,
            activity_id: newActivity.id
          }));
          await supabase
            .from("coupon_template_activities")
            .insert(couponAssociations);
        }

        toast.success(t("admin.activityCreated"));
        setOpen(false);
      }
      queryClient.invalidateQueries({
        queryKey: ["activities"]
      });
      queryClient.invalidateQueries({
        queryKey: ["admin-activities"]
      });
    } catch (error: any) {
      toast.error(error.message || t("common.error"));
    } finally {
      setIsSubmitting(false);
    }
  };
  return <Dialog open={open} onOpenChange={handleOpenChange}>
      <DialogTrigger asChild>{trigger}</DialogTrigger>
      <DialogContent className="max-w-[95vw] sm:max-w-6xl max-h-[95vh] overflow-hidden flex flex-col p-0">
        <DialogHeader className="px-6 pt-6 pb-4 border-b bg-muted/30">
          <DialogTitle className="text-2xl flex items-center gap-2">
            <Globe className="w-6 h-6 text-primary" />
            {activity ? t("admin.editActivity") : t("admin.addActivity")}
          </DialogTitle>
          <DialogDescription className="text-base">
            {activity ? t("admin.editActivityDetails") : t("admin.createActivityWithContent")}
          </DialogDescription>
        </DialogHeader>

        <ScrollArea className="px-6 h-[calc(95vh-220px)]">
          <form onSubmit={handleSubmit(onSubmit)} className="space-y-6 py-6">
            {/* Media Upload */}
            <Card className="border-primary/20 bg-gradient-to-br from-background to-muted/20">
              <CardContent className="p-6">
                <Label className="text-base font-semibold flex items-center gap-2 mb-4">
                  <Upload className="w-5 h-5 text-primary" />
                  {t("admin.activityMedia")}
                </Label>
                
                {/* Media Type Selector */}
                <div className="flex gap-2 mb-4">
                  <Button
                    type="button"
                    variant={mediaType === "image" ? "default" : "outline"}
                    size="sm"
                    onClick={() => setMediaType("image")}
                    className="flex items-center gap-2"
                  >
                    <Image className="w-4 h-4" />
                    {t("admin.image")}
                  </Button>
                  <Button
                    type="button"
                    variant={mediaType === "video" ? "default" : "outline"}
                    size="sm"
                    onClick={() => setMediaType("video")}
                    className="flex items-center gap-2"
                  >
                    <Video className="w-4 h-4" />
                    {t("admin.video") || "视频"}
                  </Button>
                </div>

                {/* Image Upload */}
                {mediaType === "image" && (
                  <div className="flex items-center gap-6">
                    {imagePreview && (
                      <div className="relative group">
                        <img src={imagePreview} alt="Preview" className="w-40 h-40 object-cover rounded-lg shadow-lg ring-2 ring-primary/20 transition-transform duration-200 group-hover:scale-105" />
                        <Button type="button" variant="destructive" size="icon" className="absolute -top-2 -right-2 h-8 w-8 shadow-lg opacity-0 group-hover:opacity-100 transition-opacity" onClick={() => {
                          setImageFile(null);
                          setImagePreview(null);
                        }}>
                          <X className="h-4 w-4" />
                        </Button>
                      </div>
                    )}
                    <Label htmlFor="image-upload" className="cursor-pointer">
                      <div className="flex flex-col items-center gap-3 px-8 py-6 border-2 border-dashed border-primary/30 rounded-lg hover:border-primary hover:bg-primary/5 transition-all duration-200">
                        <Upload className="h-8 w-8 text-primary" />
                        <div className="text-center">
                          <p className="font-medium text-sm">{t("admin.uploadImage")}</p>
                          <p className="text-xs text-muted-foreground mt-1">{t("admin.imageMaxSize")}</p>
                        </div>
                      </div>
                      <Input id="image-upload" type="file" accept="image/*" className="hidden" onChange={handleImageChange} />
                    </Label>
                  </div>
                )}

                {/* Video Upload */}
                {mediaType === "video" && (
                  <div className="space-y-4">
                    <div className="flex items-center gap-6">
                      {videoPreview && (
                        <div className="relative group">
                          <video 
                            src={videoPreview} 
                            className="w-40 h-40 object-cover rounded-lg shadow-lg ring-2 ring-primary/20"
                            muted
                            loop
                            playsInline
                            onMouseEnter={(e) => e.currentTarget.play()}
                            onMouseLeave={(e) => {
                              e.currentTarget.pause();
                              e.currentTarget.currentTime = 0;
                            }}
                          />
                          <Button type="button" variant="destructive" size="icon" className="absolute -top-2 -right-2 h-8 w-8 shadow-lg opacity-0 group-hover:opacity-100 transition-opacity" onClick={() => {
                            setVideoFile(null);
                            setVideoPreview(null);
                            setVideoDeleted(true);
                          }}>
                            <X className="h-4 w-4" />
                          </Button>
                        </div>
                      )}
                      <Label htmlFor="video-upload" className="cursor-pointer">
                        <div className="flex flex-col items-center gap-3 px-8 py-6 border-2 border-dashed border-primary/30 rounded-lg hover:border-primary hover:bg-primary/5 transition-all duration-200">
                          <Video className="h-8 w-8 text-primary" />
                          <div className="text-center">
                            <p className="font-medium text-sm">{t("admin.uploadVideo") || "上传视频"}</p>
                            <p className="text-xs text-muted-foreground mt-1">{t("admin.videoMaxSize") || "最大 50MB"}</p>
                          </div>
                        </div>
                        <Input id="video-upload" type="file" accept="video/*" className="hidden" onChange={handleVideoChange} />
                      </Label>
                    </div>
                    
                    {/* Fallback Image for Video */}
                    <div className="pt-4 border-t">
                      <Label className="text-sm font-medium mb-2 block">{t("admin.fallbackImage") || "封面图片（可选）"}</Label>
                      <p className="text-xs text-muted-foreground mb-3">{t("admin.fallbackImageDesc") || "视频加载前显示的封面图"}</p>
                      <div className="flex items-center gap-4">
                        {imagePreview && (
                          <div className="relative group">
                            <img src={imagePreview} alt="Fallback" className="w-20 h-20 object-cover rounded-lg shadow ring-2 ring-primary/20" />
                            <Button type="button" variant="destructive" size="icon" className="absolute -top-1 -right-1 h-6 w-6 shadow opacity-0 group-hover:opacity-100 transition-opacity" onClick={() => {
                              setImageFile(null);
                              setImagePreview(null);
                            }}>
                              <X className="h-3 w-3" />
                            </Button>
                          </div>
                        )}
                        <Label htmlFor="fallback-image-upload" className="cursor-pointer">
                          <div className="flex items-center gap-2 px-4 py-2 border border-dashed border-primary/30 rounded-lg hover:border-primary hover:bg-primary/5 transition-all text-sm">
                            <Image className="h-4 w-4 text-primary" />
                            <span>{t("admin.uploadFallback") || "上传封面"}</span>
                          </div>
                          <Input id="fallback-image-upload" type="file" accept="image/*" className="hidden" onChange={handleImageChange} />
                        </Label>
                      </div>
                    </div>
                  </div>
                )}
              </CardContent>
            </Card>

            {/* Multi-language Content with Tabs */}
            <Card className="border-primary/20">
              <CardContent className="p-6">
                <Label className="text-base font-semibold flex items-center gap-2 mb-4">
                  <Globe className="w-5 h-5 text-primary" />
                  {t("admin.multilingualContent")}
                </Label>
                <Tabs value={contentLangTab} onValueChange={setContentLangTab} className="w-full">
                  <TabsList className="grid w-full grid-cols-3 mb-6">
                    <TabsTrigger value="zh" className="gap-2">
                      🇨🇳 {t("admin.chinese")}
                    </TabsTrigger>
                    <TabsTrigger value="en" className="gap-2">
                      🇬🇧 {t("admin.english")}
                    </TabsTrigger>
                    <TabsTrigger value="pt" className="gap-2">
                      🇵🇹 {t("admin.portuguese")}
                    </TabsTrigger>
                  </TabsList>
                  
                  <TabsContent value="zh" className="space-y-4 mt-0">
                    <div className="space-y-2">
                      <Label htmlFor="title_zh" className="text-sm font-medium">{t("admin.title")}</Label>
                      <Input id="title_zh" {...register("title_zh")} placeholder={t("admin.enterTitle")} className="text-base" />
                      {errors.title_zh && <p className="text-sm text-destructive">{errors.title_zh.message}</p>}
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="intro_zh" className="text-sm font-medium">活动简介</Label>
                      <Input id="intro_zh" {...register("intro_zh")} placeholder="简短描述活动（显示在餐厅详情页）" className="text-base" />
                      <p className="text-xs text-muted-foreground">在餐厅详情页活动标签后显示的简短说明</p>
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="content_zh" className="text-sm font-medium">{t("admin.content")}</Label>
                      {editorsReady && contentLangTab === "zh" && <Suspense fallback={<div className="h-[200px] rounded-lg border border-border bg-muted animate-pulse" />}>
                        <Controller name="content_zh" control={control} render={({ field }) => <LazyRichTextEditor value={field.value} onChange={field.onChange} placeholder={t("admin.enterContent")} />} />
                      </Suspense>}
                      {!editorsReady && <div className="h-[200px] rounded-lg border border-border bg-muted animate-pulse" />}
                      {errors.content_zh && <p className="text-sm text-destructive">{errors.content_zh.message}</p>}
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="usage_instructions_zh" className="text-sm font-medium">活动使用方法</Label>
                      {editorsReady && contentLangTab === "zh" && <Suspense fallback={<div className="h-[200px] rounded-lg border border-border bg-muted animate-pulse" />}>
                        <Controller name="usage_instructions_zh" control={control} render={({ field }) => <LazyRichTextEditor value={field.value || ""} onChange={field.onChange} placeholder="描述如何使用此活动（可选）" />} />
                      </Suspense>}
                      {!editorsReady && <div className="h-[200px] rounded-lg border border-border bg-muted animate-pulse" />}
                      <p className="text-xs text-muted-foreground">向用户说明如何参与和使用此活动</p>
                    </div>
                  </TabsContent>
                  
                  <TabsContent value="en" className="space-y-4 mt-0">
                    <div className="space-y-2">
                      <Label htmlFor="title_en" className="text-sm font-medium">{t("admin.title")}</Label>
                      <Input id="title_en" {...register("title_en")} placeholder={t("admin.enterTitle")} className="text-base" />
                      {errors.title_en && <p className="text-sm text-destructive">{errors.title_en.message}</p>}
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="intro_en" className="text-sm font-medium">Activity Brief</Label>
                      <Input id="intro_en" {...register("intro_en")} placeholder="Short description (shown on restaurant details)" className="text-base" />
                      <p className="text-xs text-muted-foreground">Brief description shown after activity badge on restaurant page</p>
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="content_en" className="text-sm font-medium">{t("admin.content")}</Label>
                      {editorsReady && contentLangTab === "en" && <Suspense fallback={<div className="h-[200px] rounded-lg border border-border bg-muted animate-pulse" />}>
                        <Controller name="content_en" control={control} render={({ field }) => <LazyRichTextEditor value={field.value} onChange={field.onChange} placeholder={t("admin.enterContent")} />} />
                      </Suspense>}
                      {errors.content_en && <p className="text-sm text-destructive">{errors.content_en.message}</p>}
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="usage_instructions_en" className="text-sm font-medium">Usage Instructions</Label>
                      {editorsReady && contentLangTab === "en" && <Suspense fallback={<div className="h-[200px] rounded-lg border border-border bg-muted animate-pulse" />}>
                        <Controller name="usage_instructions_en" control={control} render={({ field }) => <LazyRichTextEditor value={field.value || ""} onChange={field.onChange} placeholder="Describe how to use this activity (optional)" />} />
                      </Suspense>}
                      <p className="text-xs text-muted-foreground">Explain to users how to participate and use this activity</p>
                    </div>
                  </TabsContent>
                  
                  <TabsContent value="pt" className="space-y-4 mt-0">
                    <div className="space-y-2">
                      <Label htmlFor="title_pt" className="text-sm font-medium">{t("admin.title")}</Label>
                      <Input id="title_pt" {...register("title_pt")} placeholder={t("admin.enterTitle")} className="text-base" />
                      {errors.title_pt && <p className="text-sm text-destructive">{errors.title_pt.message}</p>}
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="intro_pt" className="text-sm font-medium">Resumo da Atividade</Label>
                      <Input id="intro_pt" {...register("intro_pt")} placeholder="Descrição curta (exibida nos detalhes do restaurante)" className="text-base" />
                      <p className="text-xs text-muted-foreground">Breve descrição exibida após o distintivo da atividade na página do restaurante</p>
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="content_pt" className="text-sm font-medium">{t("admin.content")}</Label>
                      {editorsReady && contentLangTab === "pt" && <Suspense fallback={<div className="h-[200px] rounded-lg border border-border bg-muted animate-pulse" />}>
                        <Controller name="content_pt" control={control} render={({ field }) => <LazyRichTextEditor value={field.value} onChange={field.onChange} placeholder={t("admin.enterContent")} />} />
                      </Suspense>}
                      {errors.content_pt && <p className="text-sm text-destructive">{errors.content_pt.message}</p>}
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="usage_instructions_pt" className="text-sm font-medium">Instruções de Uso</Label>
                      {editorsReady && contentLangTab === "pt" && <Suspense fallback={<div className="h-[200px] rounded-lg border border-border bg-muted animate-pulse" />}>
                        <Controller name="usage_instructions_pt" control={control} render={({ field }) => <LazyRichTextEditor value={field.value || ""} onChange={field.onChange} placeholder="Descreva como usar esta atividade (opcional)" />} />
                      </Suspense>}
                      <p className="text-xs text-muted-foreground">Explique aos usuários como participar e usar esta atividade</p>
                    </div>
                  </TabsContent>
                </Tabs>
              </CardContent>
            </Card>

            {/* Date Range and Settings */}
            <Card className="border-primary/20">
              <CardContent className="p-6 space-y-6">
                <div>
                  <Label className="text-base font-semibold flex items-center gap-2 mb-4">
                    <CalendarIcon className="w-5 h-5 text-primary" />
                    {t("admin.dateSettings")}
                  </Label>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label className="text-sm font-medium">{t("admin.startDate")}</Label>
                      <Popover>
                        <PopoverTrigger asChild>
                          <Button variant="outline" className={cn("w-full justify-start text-left font-normal h-11", !startDate && "text-muted-foreground")}>
                            <CalendarIcon className="mr-2 h-4 w-4" />
                            {startDate ? format(startDate, "PPP") : <span>{t("admin.selectDate")}</span>}
                          </Button>
                        </PopoverTrigger>
                        <PopoverContent className="w-auto p-0 z-[100]" align="start">
                          <Calendar mode="single" selected={startDate} onSelect={date => setValue("start_date", date as Date)} initialFocus className="pointer-events-auto" />
                        </PopoverContent>
                      </Popover>
                    </div>
                    <div className="space-y-2">
                      <Label className="text-sm font-medium">{t("admin.endDate")}</Label>
                      <Popover>
                        <PopoverTrigger asChild>
                          <Button variant="outline" className={cn("w-full justify-start text-left font-normal h-11", !endDate && "text-muted-foreground")}>
                            <CalendarIcon className="mr-2 h-4 w-4" />
                            {endDate ? format(endDate, "PPP") : <span>{t("admin.selectDate")} ({t("admin.optional")})</span>}
                          </Button>
                        </PopoverTrigger>
                        <PopoverContent className="w-auto p-0 z-[100]" align="start">
                          <Calendar mode="single" selected={endDate} onSelect={date => setValue("end_date", date)} initialFocus className="pointer-events-auto" />
                        </PopoverContent>
                      </Popover>
                    </div>
                  </div>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="repeat_mode" className="text-sm font-medium">{t("admin.repeatMode")}</Label>
                  <Select onValueChange={value => setValue("repeat_mode", value as any)} defaultValue={watch("repeat_mode")}>
                    <SelectTrigger className="h-11">
                      <SelectValue placeholder={t("admin.selectRepeatMode")} />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="none">{t("admin.repeatNone")}</SelectItem>
                      <SelectItem value="daily">{t("admin.repeatDaily")}</SelectItem>
                      <SelectItem value="weekly">{t("admin.repeatWeekly")}</SelectItem>
                      <SelectItem value="monthly">{t("admin.repeatMonthly")}</SelectItem>
                      <SelectItem value="yearly">{t("admin.repeatYearly")}</SelectItem>
                      <SelectItem value="days_before">{t("admin.repeatDaysBefore")}</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                
                {/* Weekday selector for weekly repeat mode */}
                {watch("repeat_mode") === "weekly" && (
                  <div className="space-y-2">
                    <Label htmlFor="repeat_weekday" className="text-sm font-medium">
                      每周重复日 / Weekly on
                    </Label>
                    <Controller
                      name="repeat_weekday"
                      control={control}
                      render={({ field }) => (
                        <Select 
                          value={field.value?.toString() || ""} 
                          onValueChange={(value) => field.onChange(value ? parseInt(value) : null)}
                        >
                          <SelectTrigger className="h-11">
                            <SelectValue placeholder="选择星期几 / Select day" />
                          </SelectTrigger>
                          <SelectContent>
                            <SelectItem value="1">周一 / Monday</SelectItem>
                            <SelectItem value="2">周二 / Tuesday</SelectItem>
                            <SelectItem value="3">周三 / Wednesday</SelectItem>
                            <SelectItem value="4">周四 / Thursday</SelectItem>
                            <SelectItem value="5">周五 / Friday</SelectItem>
                            <SelectItem value="6">周六 / Saturday</SelectItem>
                            <SelectItem value="0">周日 / Sunday</SelectItem>
                          </SelectContent>
                        </Select>
                      )}
                    />
                    <p className="text-xs text-muted-foreground">
                      选择活动每周生效的日期 / Select which day this activity is valid each week
                    </p>
                  </div>
                )}

                {/* Monthly day ranges selector for monthly repeat mode */}
                {watch("repeat_mode") === "monthly" && (
                  <div className="space-y-3">
                    <Label className="text-sm font-medium">
                      {t("admin.repeatMonthDayLabel")}
                    </Label>
                    <Controller
                      name="repeat_month_day"
                      control={control}
                      render={({ field }) => {
                        const ranges = (field.value as DateRange[] | null) || [];
                        
                        const addRange = () => {
                          const newRanges = [...ranges, { start: 1, end: 1 }];
                          field.onChange(newRanges);
                        };
                        
                        const removeRange = (index: number) => {
                          const newRanges = ranges.filter((_, i) => i !== index);
                          field.onChange(newRanges.length > 0 ? newRanges : null);
                        };
                        
                        const updateRange = (index: number, key: 'start' | 'end', value: number) => {
                          const newRanges = ranges.map((range, i) => 
                            i === index ? { ...range, [key]: value } : range
                          );
                          field.onChange(newRanges);
                        };
                        
                        return (
                          <div className="space-y-3">
                            {ranges.map((range, index) => (
                              <div key={index} className="flex items-center gap-2">
                                <Select 
                                  value={range.start.toString()} 
                                  onValueChange={(value) => updateRange(index, 'start', parseInt(value))}
                                >
                                  <SelectTrigger className="h-10 w-24">
                                    <SelectValue />
                                  </SelectTrigger>
                                  <SelectContent>
                                    {Array.from({length: 31}, (_, i) => i + 1).map(day => (
                                      <SelectItem key={day} value={day.toString()}>
                                        {day}日
                                      </SelectItem>
                                    ))}
                                  </SelectContent>
                                </Select>
                                <span className="text-muted-foreground">—</span>
                                <Select 
                                  value={range.end.toString()} 
                                  onValueChange={(value) => updateRange(index, 'end', parseInt(value))}
                                >
                                  <SelectTrigger className="h-10 w-24">
                                    <SelectValue />
                                  </SelectTrigger>
                                  <SelectContent>
                                    {Array.from({length: 31}, (_, i) => i + 1).map(day => (
                                      <SelectItem key={day} value={day.toString()}>
                                        {day}日
                                      </SelectItem>
                                    ))}
                                  </SelectContent>
                                </Select>
                                <Button
                                  type="button"
                                  variant="ghost"
                                  size="icon"
                                  className="h-10 w-10 text-destructive hover:text-destructive"
                                  onClick={() => removeRange(index)}
                                >
                                  <Trash2 className="h-4 w-4" />
                                </Button>
                              </div>
                            ))}
                            <Button
                              type="button"
                              variant="outline"
                              size="sm"
                              onClick={addRange}
                              className="mt-2"
                            >
                              <Plus className="h-4 w-4 mr-2" />
                              {t("admin.addDateRange")}
                            </Button>
                          </div>
                        );
                      }}
                    />
                    <p className="text-xs text-muted-foreground">
                      {t("admin.repeatMonthDayHint")}
                    </p>
                  </div>
                )}

                {/* Yearly month and day selector for yearly repeat mode */}
                {watch("repeat_mode") === "yearly" && (
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label htmlFor="repeat_yearly_month" className="text-sm font-medium">
                        {t("admin.repeatYearlyMonthLabel")}
                      </Label>
                      <Controller
                        name="repeat_yearly_month"
                        control={control}
                        render={({ field }) => (
                          <Select 
                            value={field.value?.toString() || ""} 
                            onValueChange={(value) => field.onChange(value ? parseInt(value) : null)}
                          >
                            <SelectTrigger className="h-11">
                              <SelectValue placeholder={t("admin.repeatYearlyMonthPlaceholder")} />
                            </SelectTrigger>
                            <SelectContent>
                              <SelectItem value="1">1月 / January</SelectItem>
                              <SelectItem value="2">2月 / February</SelectItem>
                              <SelectItem value="3">3月 / March</SelectItem>
                              <SelectItem value="4">4月 / April</SelectItem>
                              <SelectItem value="5">5月 / May</SelectItem>
                              <SelectItem value="6">6月 / June</SelectItem>
                              <SelectItem value="7">7月 / July</SelectItem>
                              <SelectItem value="8">8月 / August</SelectItem>
                              <SelectItem value="9">9月 / September</SelectItem>
                              <SelectItem value="10">10月 / October</SelectItem>
                              <SelectItem value="11">11月 / November</SelectItem>
                              <SelectItem value="12">12月 / December</SelectItem>
                            </SelectContent>
                          </Select>
                        )}
                      />
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="repeat_yearly_day" className="text-sm font-medium">
                        {t("admin.repeatYearlyDayLabel")}
                      </Label>
                      <Controller
                        name="repeat_yearly_day"
                        control={control}
                        render={({ field }) => (
                          <Select 
                            value={field.value?.toString() || ""} 
                            onValueChange={(value) => field.onChange(value ? parseInt(value) : null)}
                          >
                            <SelectTrigger className="h-11">
                              <SelectValue placeholder={t("admin.repeatYearlyDayPlaceholder")} />
                            </SelectTrigger>
                            <SelectContent>
                              {Array.from({length: 31}, (_, i) => i + 1).map(day => (
                                <SelectItem key={day} value={day.toString()}>
                                  {day}日 / Day {day}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        )}
                      />
                    </div>
                    <p className="text-xs text-muted-foreground col-span-2">
                      {t("admin.repeatYearlyHint")}
                    </p>
                  </div>
                )}

                {/* Days before selector for days_before repeat mode */}
                {watch("repeat_mode") === "days_before" && (
                  <div className="space-y-2">
                    <Label htmlFor="repeat_days_before" className="text-sm font-medium">
                      {t("admin.daysBeforeLabel")}
                    </Label>
                    <Controller
                      name="repeat_days_before"
                      control={control}
                      render={({ field }) => (
                        <Input
                          type="number"
                          min={1}
                          max={30}
                          className="h-11"
                          placeholder={t("admin.daysBeforePlaceholder")}
                          value={field.value ?? ""}
                          onChange={(e) => field.onChange(e.target.value ? parseInt(e.target.value) : null)}
                        />
                      )}
                    />
                    <p className="text-xs text-muted-foreground">
                      {t("admin.daysBeforeHint")}
                    </p>
                  </div>
                )}

                <div className="space-y-2">
                  <Label htmlFor="service_type" className="text-sm font-medium">{t("admin.serviceType")}</Label>
                  <Select onValueChange={value => setValue("service_type", value as any)} defaultValue={watch("service_type")}>
                    <SelectTrigger className="h-11">
                      <SelectValue placeholder={t("admin.selectServiceType")} />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="dine_in">{t("activities.serviceType.dine_in")}</SelectItem>
                      <SelectItem value="takeaway">{t("activities.serviceType.takeaway")}</SelectItem>
                      <SelectItem value="both">{t("activities.serviceType.both")}</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                  {/* Status Selector */}
                  <div className="space-y-2">
                    <Label className="text-sm font-medium flex items-center gap-2">
                      {watch("status") === "draft" ? (
                        <FileEdit className="w-4 h-4 text-yellow-500" />
                      ) : (
                        <Send className="w-4 h-4 text-green-500" />
                      )}
                      活动状态
                    </Label>
                    <Select onValueChange={value => setValue("status", value as "draft" | "published")} value={status || "draft"}>
                      <SelectTrigger className="h-11">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="draft">
                          <span className="flex items-center gap-2">
                            <FileEdit className="w-4 h-4 text-yellow-500" />
                            草稿
                          </span>
                        </SelectItem>
                        <SelectItem value="published">
                          <span className="flex items-center gap-2">
                            <Send className="w-4 h-4 text-green-500" />
                            已发布
                          </span>
                        </SelectItem>
                      </SelectContent>
                    </Select>
                    <p className="text-xs text-muted-foreground">
                      {status === "draft" 
                        ? "草稿状态：无必填项，不显示在前端，餐厅不会收到通知" 
                        : "发布时将验证必填项"}
                    </p>
                  </div>

                  <div className={cn(
                    "flex items-center space-x-3 p-4 border rounded-lg transition-colors h-fit self-end",
                    status === "draft" ? "opacity-50 cursor-not-allowed bg-muted/30" : "hover:bg-muted/50"
                  )}>
                    <Checkbox 
                      id="pinned" 
                      checked={pinned} 
                      onCheckedChange={(checked) => setValue("pinned", checked === true)} 
                      className="data-[state=checked]:bg-primary"
                      disabled={status === "draft"}
                    />
                    <Label htmlFor="pinned" className={cn(
                      "flex items-center gap-2 text-sm font-medium",
                      status === "draft" ? "cursor-not-allowed" : "cursor-pointer"
                    )}>
                      <Pin className="w-4 h-4 text-primary" />
                      {t("admin.pinToTop")}
                    </Label>
                  </div>
                  <div className={cn(
                    "flex items-center space-x-3 p-4 border rounded-lg transition-colors h-fit self-end",
                    status === "draft" ? "opacity-50 cursor-not-allowed bg-muted/30" : "hover:bg-muted/50"
                  )}>
                    <Checkbox 
                      id="visible" 
                      checked={visible} 
                      onCheckedChange={(checked) => setValue("visible", checked === true)} 
                      className="data-[state=checked]:bg-primary"
                      disabled={status === "draft"}
                    />
                    <Label htmlFor="visible" className={cn(
                      "flex items-center gap-2 text-sm font-medium",
                      status === "draft" ? "cursor-not-allowed" : "cursor-pointer"
                    )}>
                      <Globe className="w-4 h-4 text-primary" />
                      显示活动
                      {status === "draft" && <span className="text-xs text-muted-foreground">(草稿默认关闭)</span>}
                    </Label>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="sort_order" className="text-sm font-medium flex items-center gap-2">
                      <ArrowUpDown className="w-4 h-4 text-primary" />
                      {t("admin.sortOrder")}
                    </Label>
                    <Input id="sort_order" type="number" {...register("sort_order", {
                    valueAsNumber: true
                  })} className="h-11" placeholder="0" />
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* Badge Display Settings */}
            <Card className="border-primary/20">
              <CardContent className="p-6">
                <Label className="text-base font-semibold flex items-center gap-2 mb-4">
                  <Badge className="w-5 h-5 text-primary" />
                  {t("admin.form.badgeSettings")}
                </Label>
                <Tabs defaultValue="zh" className="w-full">
                  <TabsList className="grid w-full grid-cols-3 mb-4">
                    <TabsTrigger value="zh">🇨🇳 {t("admin.chinese")}</TabsTrigger>
                    <TabsTrigger value="en">🇬🇧 {t("admin.english")}</TabsTrigger>
                    <TabsTrigger value="pt">🇵🇹 {t("admin.portuguese")}</TabsTrigger>
                  </TabsList>
                  
                  <TabsContent value="zh" className="space-y-3">
                    <div className="space-y-2">
                      <Label htmlFor="badge_text_zh" className="text-sm">{t("admin.form.badgeText")} ({t("admin.chinese")}) <span className="text-destructive">*</span></Label>
                      <Input id="badge_text_zh" {...register("badge_text_zh")} />
                      {errors.badge_text_zh && <p className="text-sm text-destructive">{errors.badge_text_zh.message}</p>}
                      <p className="text-xs text-muted-foreground">{t("admin.form.badgeHint")}</p>
                    </div>
                  </TabsContent>
                  
                  <TabsContent value="en" className="space-y-3">
                    <div className="space-y-2">
                      <Label htmlFor="badge_text_en" className="text-sm">{t("admin.form.badgeText")} ({t("admin.english")}) <span className="text-destructive">*</span></Label>
                      <Input id="badge_text_en" {...register("badge_text_en")} />
                      {errors.badge_text_en && <p className="text-sm text-destructive">{errors.badge_text_en.message}</p>}
                      <p className="text-xs text-muted-foreground">{t("admin.form.badgeHint")}</p>
                    </div>
                  </TabsContent>
                  
                  <TabsContent value="pt" className="space-y-3">
                    <div className="space-y-2">
                      <Label htmlFor="badge_text_pt" className="text-sm">{t("admin.form.badgeText")} ({t("admin.portuguese")}) <span className="text-destructive">*</span></Label>
                      <Input id="badge_text_pt" {...register("badge_text_pt")} />
                      {errors.badge_text_pt && <p className="text-sm text-destructive">{errors.badge_text_pt.message}</p>}
                      <p className="text-xs text-muted-foreground">{t("admin.form.badgeHint")}</p>
                    </div>
                  </TabsContent>
                </Tabs>
                
                <div className="space-y-2 mt-4">
                  <Label htmlFor="badge_color" className="text-sm">{t("admin.form.badgeColor")}</Label>
                  <Controller name="badge_color" control={control} render={({
                  field
                }) => <div className="flex items-center gap-3">
                        <Input id="badge_color" type="color" value={field.value || "#9b87f5"} onChange={e => field.onChange(e.target.value)} className="w-20 h-11 cursor-pointer" />
                        <Input value={field.value || "#9b87f5"} onChange={e => field.onChange(e.target.value)} placeholder="#9b87f5" className="flex-1" />
                      </div>} />
                  <div className="flex items-center gap-2 mt-2">
                    <span className="text-xs text-muted-foreground">{t("admin.form.preview")}:</span>
                    <Badge style={{
                    backgroundColor: watch("badge_color") || "#9b87f5"
                  }} className="text-white">
                      {watch("badge_text_zh") || watch("title_zh") || "Sample"}
                    </Badge>
                  </div>
                </div>

                {/* Discount Settings */}
                <div className="border-t pt-4 mt-4">
                  <Label className="text-sm font-medium flex items-center gap-2 mb-3">
                    💰 优惠设置 / Discount Settings
                  </Label>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label htmlFor="discount_type" className="text-sm">折扣类型 / Discount Type</Label>
                      <Controller 
                        name="discount_type" 
                        control={control} 
                        render={({ field }) => (
                          <Select 
                            value={field.value || "none"} 
                            onValueChange={(value) => field.onChange(value === "none" ? null : value)}
                          >
                            <SelectTrigger className="h-11">
                              <SelectValue placeholder="选择折扣类型" />
                            </SelectTrigger>
                            <SelectContent>
                              <SelectItem value="none">无优惠 / No Discount</SelectItem>
                              <SelectItem value="percentage">百分比折扣 / Percentage</SelectItem>
                              <SelectItem value="fixed_amount">固定金额 / Fixed Amount</SelectItem>
                            </SelectContent>
                          </Select>
                        )} 
                      />
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="discount_value" className="text-sm">
                        折扣值 / Discount Value
                        {watch("discount_type") === "percentage" && " (%)"}
                        {watch("discount_type") === "fixed_amount" && " (€)"}
                      </Label>
                      <Input 
                        id="discount_value" 
                        type="number" 
                        step="0.01"
                        {...register("discount_value", { valueAsNumber: true })} 
                        className="h-11" 
                        placeholder={watch("discount_type") === "percentage" ? "例如: 20 (表示8折)" : "例如: 5 (表示减5€)"}
                        disabled={!watch("discount_type")}
                      />
                      <p className="text-xs text-muted-foreground">
                        {watch("discount_type") === "percentage" 
                          ? "输入折扣百分比，如 20 表示打8折（减20%）" 
                          : watch("discount_type") === "fixed_amount"
                          ? "输入固定减免金额（欧元）"
                          : "先选择折扣类型"}
                      </p>
                    </div>
                    
                    {/* Discount Key */}
                    <div className="space-y-2">
                      <Label htmlFor="discount_key" className="text-sm">折扣标识 / Discount Key</Label>
                      <Input 
                        id="discount_key"
                        type="text"
                        {...register("discount_key")} 
                        className="h-11" 
                        placeholder="例如: SUMMER2025, VIP_DISCOUNT"
                        disabled={!watch("discount_type")}
                      />
                      <p className="text-xs text-muted-foreground">
                        用于外部系统识别的折扣标识符
                      </p>
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* Associated Restaurants */}
            <Card className="border-primary/20">
              <CardContent className="p-6">
                <Label className="text-base font-semibold flex items-center gap-2 mb-4">
                  <Store className="w-5 h-5 text-primary" />
                  {t("admin.associatedRestaurants")}
                </Label>
                
                {/* Search Input */}
                <div className="relative mb-3">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                  <Input
                    placeholder={t("admin.searchRestaurants") || "搜索餐厅..."}
                    value={restaurantSearch}
                    onChange={(e) => setRestaurantSearch(e.target.value)}
                    className="pl-9 h-10"
                  />
                  {restaurantSearch && (
                    <Button
                      type="button"
                      variant="ghost"
                      size="icon"
                      className="absolute right-1 top-1/2 -translate-y-1/2 h-7 w-7"
                      onClick={() => setRestaurantSearch("")}
                    >
                      <X className="h-3.5 w-3.5" />
                    </Button>
                  )}
                </div>
                
                <ScrollArea className="h-64 border rounded-lg p-4 bg-muted/20">
                  <div className="space-y-2">
                    {isRestaurantsLoading && Array.from({ length: hasRestaurantSearch ? 6 : 4 }).map((_, index) => (
                      <div key={index} className="flex items-center space-x-3 p-3 rounded-md border border-transparent">
                        <Skeleton className="h-4 w-4 rounded-sm" />
                        <Skeleton className="h-4 flex-1" />
                      </div>
                    ))}

                    {!isRestaurantsLoading && restaurants?.map(restaurant => (
                      <div key={restaurant.id} className="flex items-center space-x-3 p-3 rounded-md hover:bg-background transition-colors border border-transparent hover:border-primary/30">
                        <Checkbox
                          id={restaurant.id}
                          checked={selectedRestaurantIds.has(restaurant.id)}
                          onCheckedChange={checked => {
                            if (checked) {
                              setSelectedRestaurants([...selectedRestaurants, restaurant.id]);
                            } else {
                              setSelectedRestaurants(selectedRestaurants.filter(id => id !== restaurant.id));
                            }
                          }}
                          className="data-[state=checked]:bg-primary"
                        />
                        <Label htmlFor={restaurant.id} className="cursor-pointer flex-1 font-normal">
                          {restaurant.name}
                        </Label>
                        {selectedRestaurantIds.has(restaurant.id) && (
                          <Badge variant="secondary" className="text-xs">已选</Badge>
                        )}
                      </div>
                    ))}

                    {!isRestaurantsLoading && restaurants?.length === 0 && (
                      <p className="text-sm text-muted-foreground text-center py-4">
                        {hasRestaurantSearch ? t("common.noResults") || "没有找到匹配的餐厅" : "请输入关键词搜索餐厅"}
                      </p>
                    )}
                  </div>
                </ScrollArea>
                <p className="text-xs text-muted-foreground mt-2">
                  已选择 {selectedRestaurants.length} 个餐厅
                  {!hasRestaurantSearch && " · 默认仅显示前 40 个，请搜索以缩小范围"}
                </p>
              </CardContent>
            </Card>

            {/* Submit Buttons */}
            <div className="flex justify-end gap-3 pt-4 border-t sticky bottom-0 bg-background pb-[16px]">
              <Button type="button" variant="outline" onClick={() => setOpen(false)} className="min-w-[100px]">
                {t("common.cancel")}
              </Button>
              <Button type="submit" disabled={isSubmitting} className="min-w-[100px] bg-primary hover:bg-primary/90">
                {isSubmitting ? <>
                    <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin mr-2" />
                    {t("common.saving")}
                  </> : t("common.save")}
              </Button>
            </div>
          </form>
        </ScrollArea>

        {/* Image Crop Dialog */}
        {tempImageFile && (
          <ImageCropDialog
            open={showCropDialog}
            onOpenChange={setShowCropDialog}
            imageFile={tempImageFile}
            onCropComplete={handleCropComplete}
          />
        )}
      </DialogContent>
    </Dialog>;
}